using System;using System.Collections.Generic;using System.IO;using System.Text;namespace LemonFramework.UProfiler.Core{    [Serializable]    public struct DevicePowerConsumeInfo : IBinarySerializable    {        //Frame index        public int frameIndex;        //Battery capacity        public int capacity;        //Temperature        public int temperature;        //Battery voltage        public float batteryV;        //Battery capacity (mAh)        public int batteryCapacity;        //Battery charge counter        public int batteryChargeCounter;        //Battery current (now)        public int batteryCurrentNow;        //Battery power (W)        public float batteryPower;        //Estimated hours remaining        public float useLeftHours;        //CPU temperature        public int cpuTemperate;        public void Serialize(BinaryWriter writer)        {            writer.Write(frameIndex);            writer.Write(capacity);            writer.Write(temperature);            writer.Write(batteryV);            writer.Write(batteryCapacity);            writer.Write(batteryChargeCounter);            writer.Write(batteryCurrentNow);            writer.Write(batteryPower);            writer.Write(useLeftHours);            writer.Write(cpuTemperate);        }        public void DeSerialize(BinaryReader reader)        {            frameIndex = reader.ReadInt32();            capacity = reader.ReadInt32();            temperature = reader.ReadInt32();            batteryV = reader.ReadSingle();            batteryCapacity = reader.ReadInt32();            batteryChargeCounter = reader.ReadInt32();            batteryCurrentNow = reader.ReadInt32();            batteryPower = reader.ReadSingle();            useLeftHours = reader.ReadSingle();            cpuTemperate = reader.ReadInt32();        }        public override string ToString()        {            return $"FrameIndex:{frameIndex}\n" + $"Capacity:{capacity}\n" + $"Temperature:{temperature}\n" +                   $"BatteryV:{batteryV}\n" + $"BatteryCapacity:{batteryCapacity}\n" +                   $"BatteryChargeCounter:{batteryChargeCounter}\n" + $"BatteryCurrentNow:{batteryCurrentNow}\n" +                   $"BatteryPower:{batteryPower}\n" + $"UseLeftHours:{useLeftHours}\n" +                   $"CpuTemperate:{cpuTemperate}\n";        }    }    [Serializable]    public class DevicePowerConsumeInfos : IBinarySerializable    {        public List<DevicePowerConsumeInfo> devicePowerConsumeInfos = new List<DevicePowerConsumeInfo>();        private StringBuilder _stringBuilder = new StringBuilder();        public void DeSerialize(BinaryReader reader)        {            int count = reader.ReadInt32();            for (int i = 0; i < count; i++)            {                var tempData = new DevicePowerConsumeInfo();                tempData.DeSerialize(reader);                devicePowerConsumeInfos.Add(tempData);            }        }        public void Serialize(BinaryWriter writer)        {            writer.Write(devicePowerConsumeInfos.Count);            for (int i = 0; i < devicePowerConsumeInfos.Count; i++)            {                devicePowerConsumeInfos[i].Serialize(writer);            }        }        public override string ToString()        {            _stringBuilder.Clear();            for (int i = 0; i < devicePowerConsumeInfos.Count; i++)            {                _stringBuilder.Append(devicePowerConsumeInfos[i].ToString());                _stringBuilder.Append('\n');            }            return _stringBuilder.ToString();        }    }}